CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;
CREATE TABLE "Rooms" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "RoomNumber" character varying(50) NOT NULL,
    "Description" character varying(100),
    "Capacity" integer NOT NULL,
    "IsActive" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_Rooms" PRIMARY KEY ("Id")
);

CREATE TABLE "Software" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" character varying(200) NOT NULL,
    "Description" character varying(500),
    "Version" character varying(50),
    "DownloadUrl" character varying(500),
    "IsApproved" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_Software" PRIMARY KEY ("Id")
);

CREATE TABLE "Users" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Username" character varying(100) NOT NULL,
    "PasswordHash" character varying(255) NOT NULL,
    "Role" text NOT NULL,
    "FullName" character varying(100),
    "IsActive" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "LastLoginAt" timestamp with time zone,
    CONSTRAINT "PK_Users" PRIMARY KEY ("Id")
);

CREATE TABLE "PCs" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "MacAddress" character varying(50) NOT NULL,
    "IpAddress" character varying(50),
    "SubnetMask" character varying(50),
    "DefaultGateway" character varying(50),
    "RoomId" integer NOT NULL,
    "Hostname" character varying(100),
    "OperatingSystem" character varying(100),
    "Status" text NOT NULL,
    "LastSeen" timestamp with time zone NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_PCs" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_PCs_Rooms_RoomId" FOREIGN KEY ("RoomId") REFERENCES "Rooms" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "Policies" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" character varying(100) NOT NULL,
    "Description" character varying(500),
    "RoomId" integer NOT NULL,
    "ResetWallpaperOnStartup" boolean NOT NULL,
    "EnableAccessControl" boolean NOT NULL,
    "AutoShutdownEnabled" boolean NOT NULL,
    "AutoShutdownIdleMinutes" integer,
    "ScheduledShutdownTime" interval,
    "BlockUnauthorizedApplications" boolean NOT NULL,
    "MonitorApplicationUsage" boolean NOT NULL,
    "MonitorWebsiteUsage" boolean NOT NULL,
    "IsActive" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone,
    CONSTRAINT "PK_Policies" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_Policies_Rooms_RoomId" FOREIGN KEY ("RoomId") REFERENCES "Rooms" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "SoftwareRequests" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "UserId" integer NOT NULL,
    "SoftwareId" integer NOT NULL,
    "Reason" character varying(500),
    "Status" text NOT NULL,
    "RequestedAt" timestamp with time zone NOT NULL,
    "ReviewedAt" timestamp with time zone,
    "ReviewedByUserId" integer,
    CONSTRAINT "PK_SoftwareRequests" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_SoftwareRequests_Software_SoftwareId" FOREIGN KEY ("SoftwareId") REFERENCES "Software" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_SoftwareRequests_Users_ReviewedByUserId" FOREIGN KEY ("ReviewedByUserId") REFERENCES "Users" ("Id") ON DELETE SET NULL,
    CONSTRAINT "FK_SoftwareRequests_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "Alerts" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "PCId" integer NOT NULL,
    "UserId" integer NOT NULL,
    "Title" character varying(200) NOT NULL,
    "Message" character varying(1000) NOT NULL,
    "Severity" text NOT NULL,
    "Type" text NOT NULL,
    "IsAcknowledged" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "AcknowledgedAt" timestamp with time zone,
    CONSTRAINT "PK_Alerts" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_Alerts_PCs_PCId" FOREIGN KEY ("PCId") REFERENCES "PCs" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_Alerts_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "HardwareMetrics" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "PCId" integer NOT NULL,
    "Timestamp" timestamp with time zone NOT NULL,
    "CpuUsage" double precision,
    "CpuTemperature" double precision,
    "MemoryUsage" double precision,
    "MemoryUsed" bigint,
    "MemoryTotal" bigint,
    "GpuUsage" double precision,
    "GpuTemperature" double precision,
    "GpuMemoryUsed" bigint,
    "GpuMemoryTotal" bigint,
    "DiskUsage" double precision,
    "DiskUsed" bigint,
    "DiskTotal" bigint,
    "DiskReadSpeed" double precision,
    "DiskWriteSpeed" double precision,
    CONSTRAINT "PK_HardwareMetrics" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_HardwareMetrics_PCs_PCId" FOREIGN KEY ("PCId") REFERENCES "PCs" ("Id") ON DELETE CASCADE
);

CREATE TABLE "NetworkMetrics" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "PCId" integer NOT NULL,
    "Timestamp" timestamp with time zone NOT NULL,
    "DownloadSpeed" double precision,
    "UploadSpeed" double precision,
    "BytesReceived" bigint,
    "BytesSent" bigint,
    "Latency" double precision,
    "PacketLoss" double precision,
    "IsConnected" boolean,
    "NetworkInterface" text,
    CONSTRAINT "PK_NetworkMetrics" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_NetworkMetrics_PCs_PCId" FOREIGN KEY ("PCId") REFERENCES "PCs" ("Id") ON DELETE CASCADE
);

CREATE TABLE "PCHardwareConfigs" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "PCId" integer NOT NULL,
    "Processor" character varying(100),
    "GraphicsCard" character varying(100),
    "Motherboard" character varying(100),
    "RamCapacity" bigint,
    "StorageCapacity" bigint,
    "StorageType" character varying(50),
    "AppliedAt" timestamp with time zone NOT NULL,
    "IsActive" boolean NOT NULL,
    CONSTRAINT "PK_PCHardwareConfigs" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_PCHardwareConfigs_PCs_PCId" FOREIGN KEY ("PCId") REFERENCES "PCs" ("Id") ON DELETE CASCADE
);

CREATE TABLE "SoftwareInstalled" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "PCId" integer NOT NULL,
    "SoftwareId" integer NOT NULL,
    "InstalledVersion" character varying(50),
    "InstalledAt" timestamp with time zone NOT NULL,
    "UninstalledAt" timestamp with time zone,
    "IsActive" boolean NOT NULL,
    CONSTRAINT "PK_SoftwareInstalled" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_SoftwareInstalled_PCs_PCId" FOREIGN KEY ("PCId") REFERENCES "PCs" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_SoftwareInstalled_Software_SoftwareId" FOREIGN KEY ("SoftwareId") REFERENCES "Software" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "SoftwareUsageHistory" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "PCId" integer NOT NULL,
    "ApplicationName" character varying(200) NOT NULL,
    "StartTime" timestamp with time zone NOT NULL,
    "EndTime" timestamp with time zone,
    "Duration" interval,
    "CreatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_SoftwareUsageHistory" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_SoftwareUsageHistory_PCs_PCId" FOREIGN KEY ("PCId") REFERENCES "PCs" ("Id") ON DELETE CASCADE
);

CREATE TABLE "UserLogs" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "UserId" integer NOT NULL,
    "PCId" integer,
    "Action" character varying(100) NOT NULL,
    "Details" character varying(500),
    "Timestamp" timestamp with time zone NOT NULL,
    "IpAddress" text,
    CONSTRAINT "PK_UserLogs" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_UserLogs_PCs_PCId" FOREIGN KEY ("PCId") REFERENCES "PCs" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_UserLogs_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "WebsiteUsageHistory" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "PCId" integer NOT NULL,
    "Url" character varying(500) NOT NULL,
    "Domain" character varying(200),
    "VisitedAt" timestamp with time zone NOT NULL,
    "VisitCount" integer NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_WebsiteUsageHistory" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_WebsiteUsageHistory_PCs_PCId" FOREIGN KEY ("PCId") REFERENCES "PCs" ("Id") ON DELETE CASCADE
);

CREATE INDEX "IX_Alerts_PCId" ON "Alerts" ("PCId");

CREATE INDEX "IX_Alerts_UserId" ON "Alerts" ("UserId");

