CREATE INDEX "IX_NetworkMetrics_PCId_Timestamp" ON "NetworkMetrics" ("PCId", "Timestamp");

CREATE INDEX "IX_PCHardwareConfigs_PCId" ON "PCHardwareConfigs" ("PCId");

