CREATE UNIQUE INDEX "IX_Software_Name" ON "Software" ("Name");

CREATE UNIQUE INDEX "IX_SoftwareInstalled_PCId_SoftwareId" ON "SoftwareInstalled" ("PCId", "SoftwareId");

CREATE INDEX "IX_SoftwareInstalled_SoftwareId" ON "SoftwareInstalled" ("SoftwareId");

CREATE INDEX "IX_SoftwareRequests_ReviewedByUserId" ON "SoftwareRequests" ("ReviewedByUserId");

CREATE INDEX "IX_SoftwareRequests_SoftwareId" ON "SoftwareRequests" ("SoftwareId");

CREATE INDEX "IX_SoftwareRequests_UserId" ON "SoftwareRequests" ("UserId");

CREATE INDEX "IX_SoftwareUsageHistory_PCId_StartTime" ON "SoftwareUsageHistory" ("PCId", "StartTime");

CREATE INDEX "IX_UserLogs_PCId" ON "UserLogs" ("PCId");

CREATE INDEX "IX_UserLogs_UserId_Timestamp" ON "UserLogs" ("UserId", "Timestamp");

